    choices: [
        { id: 1, text: 'Взять сокровища и уйти', reward: { strength: 3, agility: 2 }, nextCard: '8T_1', task: 'Раскрась страницу с сокровищем (ДО/ПОСЛЕ)' },
        { id: 2, text: 'Взять дневник Элиры и узнать правду (🧠17)', requireStat: { stat: 'intelligence', min: 17 }, reward: { intelligence: 5 }, nextCard: '8T_1', task: 'Раскрась страницу с дневником (ДО/ПОСЛЕ)' },
        { id: 3, text: 'Отказаться от всего (🎫4)', skipCost: 4, isPremium: true, reward: { all: 3 }, nextCard: '8T_1', task: null }
    ]
